propData.styleConfig:
#domId { padding-top: 16px; }
#domId button { width: 100%; height: 44px; background: #2563eb; color: #fff; border-color: #2563eb; font-size: 16px; font-weight: 600; border-radius: 6px; }
#domId button:hover { background: #1d4ed8; border-color: #1d4ed8; color: #fff; }

#domId { height: 100%; overflow: auto; background: #f8fafc; border: 1px solid #dbeafe; border-radius: 6px; padding: 8px 0; }
#domId .el-tree-node__content { height: 36px; color: #334155; }
#domId .el-tree-node.is-current > .el-tree-node__content { background: #dbeafe; color: #1d4ed8; }

#domId { height: 100%; }
#domId .el-table__header th, #domId .el-table__header tr { background-color: #eff6ff; color: #0f172a; font-weight: 600; }
#domId .el-table__body tr:nth-child(even) { background-color: #f8fafc; }
#domId .el-table__body td { color: #1f2937; }
